args.sparql:
SELECT ?game ?attendance WHERE {
  {
    # Dodgers home, Phillies away
    ?game wdt:P31 wd:Q39708;
          wdt:P1080 wd:Q5442;
          wdt:P1152 wd:Q6702.
    ?game wdt:P585 ?date.
    ?game wdt:P5419 ?attendance.
    BIND(YEAR(?date) AS ?year)
    FILTER(?year IN (1977, 1978, 2008, 2009))
  }
  UNION
  {
    # Phillies home, Dodgers away
    ?game wdt:P31 wd:Q39708;
          wdt:P1080 wd:Q6702;
          wdt:P1152 wd:Q5442.
    ?game wdt:P585 ?date.
    ?game wdt:P5419 ?attendance.
    BIND(YEAR(?date) AS ?year)
    FILTER(?year IN (1977, 1978, 2008, 2009))
  }
  ?game wdt:P127 ?series.
  ?series rdfs:label ?seriesLabel.
  FILTER(CONTAINS(LCASE(STR(?seriesLabel)), "national league championship series") && LANG(?seriesLabel) = 'en')
}
ORDER BY DESC(?attendance)
LIMIT 1

